      to: to,
      subject: subject,
      html: html,
      text: text,
      from: from,
      reply_to: reply_to,
      cc: cc,
      bcc: bcc,
      attachments: attachments
    )

    mail(
      to: normalize_recipients(to),
      from: from || default_from_address,
      subject: subject,
      reply_to: reply_to,
      cc: normalize_recipients(cc),
      bcc: normalize_recipients(bcc)
    ) do |format|
      format.html { render html: (html || ""), layout: false }
      format.text { render plain: (text || ""), layout: false }
    end
  end

  private

  def default_from_address
    ENV.fetch("DEFAULT_FROM_EMAIL", "no-reply@example.com")
  end

  def normalize_recipients(value)
    return nil if value.nil?
    return value if value.is_a?(Array)
    value.to_s.split(",").map(&:strip).reject(&:empty?)
  end

  def build_sendgrid_payload(to:, subject:, html:, text:, from:, reply_to:, cc:, bcc:, attachments:)
    {
      personalizations: [
        {
          to: normalize_recipients(to).map { |e| { email: e } },
          cc: normalize_recipients(cc)&.map { |e| { email: e } },
          bcc: normalize_recipients(bcc)&.map { |e| { email: e } }
        }.compact
      ],
      from: { email: (from || default_from_address) },
      reply_to: reply_to ? { email: reply_to } : nil,
      subject: subject,
      content: build_content(html: html, text: text),
      attachments: build_attachments(attachments)
    }.compact
  end

  def build_content(html:, text:)
    content = []
    content << { type: "text/plain", value: text.to_s } if text
    content << { type: "text/html", value: html.to_s } if html
    content = [{ type: "text/plain", value: "" }] if content.empty?
    content
  end

  def build_attachments(attachments)
    return nil if attachments.nil? || attachments.empty?

    attachments.map do |att|
      if att.is_a?(Hash)
        filename = att.fetch(:filename)
