require "net/http"
require "json"
require "base64"

class SendgridDeliveryMethod
  SENDGRID_URI = URI("https://api.sendgrid.com/v3/mail/send")

  attr_accessor :settings

  def initialize(settings = {})
    @settings = settings || {}
  end

  def deliver!(mail)
    api_key = settings[:api_key] || ENV["SENDGRID_API_KEY"]
    raise "Missing SendGrid API key (SENDGRID_API_KEY)" if api_key.to_s.strip.empty?

    payload = extract_payload(mail)
    response = post_sendgrid(api_key, payload)

    unless response.is_a?(Net::HTTPSuccess) || response.code.to_i == 202
      raise "SendGrid delivery failed (#{response.code}): #{response.body}"
    end

    response
  end

  private

  def extract_payload(mail)
    if mail.respond_to?(:message) && mail.message.respond_to?(:mailer) && mail.message.mailer.respond_to?(:instance_variable_get)
      mailer = mail.message.mailer
      payload = mailer.instance_variable_get(:@sendgrid_payload)
      return payload if payload.is_a?(Hash)
    end

    build_payload_from_mail(mail)
  end

  def build_payload_from_mail(mail)
    to = Array(mail.to).compact
    cc = Array(mail.cc).compact
    bcc = Array(mail.bcc).compact

    html_part = mail.html_part&.body&.decoded
    text_part = mail.text_part&.body&.decoded

    if html_part.nil? && text_part.nil?
      body = mail.body&.decoded.to_s
      if mail.content_type.to_s.include?("text/html")
        html_part = body
      else
        text_part = body
      end
    end

    attachments = mail.attachments.map do |a|
      {
        filename: a.filename,
        type: a.mime_type,
        disposition: "attachment",
        content: Base64.strict_encode64(a.body.decoded.to_s.b)
      }
    end

    {
      personalizations: [
        {
          to: to.map { |e| { email: e } },
          cc: cc.any? ? cc.map { |e| { email: e } } : nil,
          bcc: bcc.any? ? bcc.map { |e| { email: e } } : nil
        }.compact
      ],
      from: { email: (mail.from&.first || ENV.fetch("DEFAULT_FROM_EMAIL", "no-reply@example.com")) },
      reply_to: mail.reply_to&.first ? { email: mail.reply_to.first } : nil,
      subject: mail.subject.to_s,
      content: build_content(html_part, text_part),
      attachments: attachments.any? ? attachments : nil
    }.compact
  end

  def build_content(html, text)
    content = []
    content << { type: "text/plain", value: text.to_s } if text
    content << { type: "text/html", value: html.to_s } if html
    content = [{ type: "text/plain", value: "" }] if content.empty?
    content
  end

  def post_sendgrid(api_key, payload)
    http = Net::HTTP.new(SENDGRID_URI.host, SENDGRID_URI.port)
    http.use_ssl = true
    http.open_timeout = (settings[:open_timeout] || 5).to_i
    http.read_timeout = (settings[:read_timeout] || 15).to_i

    req = Net::HTTP::Post.new(SENDGRID_URI.request_uri)
    req["Authorization"] = "Bearer #{api_key}"
    req["Content-Type"] = "application/json"
    req.body = JSON.generate(payload)

    http.request(req)
  end
end

