Rails.application.configure do
  config.action_mailer.delivery_method = :sendgrid
  config.action_mailer.deliver_later_queue_name = :mailers

  config.action_mailer.delivery_methods ||= {}
  config.action_mailer.delivery_methods[:sendgrid] = SendgridDeliveryMethod

  config.action_mailer.sendgrid_settings = {
    api_key: ENV["SENDGRID_API_KEY"],
    open_timeout: ENV.fetch("SENDGRID_OPEN_TIMEOUT", "5"),
    read_timeout: ENV.fetch("SENDGRID_READ_TIMEOUT", "15")
  }

  config.action_mailer.sendgrid_settings.each do |k, v|
    config.action_mailer.delivery_method.settings[k] = v if config.action_mailer.delivery_method.respond_to?(:settings)
  end
end